const App: React.FC = () => {
  const [selectedProductForChat, setSelectedProductForChat] = useState<Product | null>(null);
  const [isChatOpen, setIsChatOpen] = useState(false);

  useEffect(() => {
    const observerOptions = {
      root: null,
      rootMargin: '0px',
      threshold: 0.1,
    };

    const handleIntersect = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add('active');
        }
      });
    };

    const observer = new IntersectionObserver(handleIntersect, observerOptions);
    const elements = document.querySelectorAll('.reveal, .reveal-stagger');
    elements.forEach((el) => observer.observe(el));

    return () => observer.disconnect();
  }, []);

  const handleOpenChat = (product: Product) => {
    setSelectedProductForChat(product);
    setIsChatOpen(true);
  };

  return (
    <div className="min-h-screen font-sans text-gray-700 bg-white">
      <Header />
      <Hero />
      <div className="reveal"><CategorySection /></div>

      {/* Intro Article */}
      <section className="py-20 bg-white">
        <div className="container mx-auto px-4 max-w-4xl text-center">
          <h2 className="text-3xl md:text-5xl font-serif font-bold text-gray-800 mb-8 leading-tight">
            เปลี่ยนถุงกระสอบเหลือใช้ <br/>
            <span className="text-primary italic underline decoration-accent">ให้เป็นทุนคืนสู่ธุรกิจของคุณ</span>
          </h2>
          <p className="text-xl text-gray-600 leading-relaxed mb-10">
            เราคือผู้นำด้านการ รับซื้อถุงกระสอบมือสอง อันดับต้นของไทย 
            ไม่ว่าคุณจะเป็นร้านขายข้าวสาร ฟาร์มเกษตร หรือโรงงานอุตสาหกรรม 
            เรายินดีตีราคารับซื้อถึงที่ ด้วยมาตรฐานที่เป็นธรรมและเป็นมืออาชีพ
          </p>
          <div className="flex justify-center gap-4">
             <div className="w-12 h-1.5 bg-primary rounded-full"></div>
             <div className="w-12 h-1.5 bg-accent rounded-full"></div>
             <div className="w-12 h-1.5 bg-primary rounded-full"></div>
          </div>
        </div>
      </section>

      <div className="reveal">
        <ProductSection 
          title="รายการรับซื้อยอดนิยม" 
          products={featuredSacks} 
          onChatOpen={handleOpenChat}
        />
      </div>

      <div className="reveal"><PriceTableSection /></div>
      <div className="reveal"><TrustSection /></div>
      <div className="reveal"><BenefitSection /></div>
      <div className="reveal"><FeaturesSection /></div>
      <div className="reveal"><Testimonials /></div>

      {/* Brand Partners */}
      <div className="py-16 bg-light border-t border-b border-gray-100 reveal">
        <div className="container mx-auto px-4">
          <p className="text-center text-xs font-bold uppercase tracking-widest text-gray-400 mb-10">Trusted by Industry Partners</p>
          <div className="flex justify-between items-center opacity-40 grayscale hover:grayscale-0 transition-all duration-500 overflow-x-auto gap-12 text-center">
             <div className="text-2xl font-bold whitespace-nowrap">AGRI-TECH</div>
             <div className="text-2xl font-bold whitespace-nowrap">RICE-MILL CO.</div>
